---
import { cn } from "@/registry/bejamas-mira/lib/utils";
import { Button } from "../button";
import type { Props as ButtonProps } from "../button/Button.astro";

type Props = ButtonProps & {
  class?: string;
  /** Radix-like: render wrapper so the child can be the interactive element */
  asChild?: boolean;
};

const { class: className = "", asChild = false, ...rest } = Astro.props as Props;
---

{
  asChild ? (
    <div data-slot="popover-trigger" data-as-child class={cn("cn-popover-trigger", "inline-flex items-center", className)}>
      <slot />
    </div>
  ) : (
    <Button
      data-slot="popover-trigger"
      class={cn("cn-popover-trigger", "inline-flex items-center", className)}
      {...rest as any}
    >
      <slot />
    </Button>
  )
}

export { default as Popover } from "./Popover.astro";
export { default as PopoverTrigger } from "./PopoverTrigger.astro";
export { default as PopoverContent } from "./PopoverContent.astro";
export { default as PopoverClose } from "./PopoverClose.astro";
export { default as PopoverHeader } from "./PopoverHeader.astro";
export { default as PopoverTitle } from "./PopoverTitle.astro";
export { default as PopoverDescription } from "./PopoverDescription.astro";
